    "pdf_audit_view_tierb_diff_view_btn": "ایک بحالی پاس چلانے کا فیصلہ کرنے سے پہلے آخری سیو کے دوران غائب ہوئے الفاظ کا جائزہ لیں۔ صرف پڑھنے کے لیے — جب تک آپ بحال کرنے کا انتخاب نہیں کرتے کچھ نہیں بدلتا۔",
    "pdf_audit_view_tierb_rerun_restore_btn": "گم شدہ ماخذ الفاظ کو دستاویز میں واپس جوڑتا ہے اور ٹیگ کردہ PDF کو دوبارہ بناتا ہے۔ وہ الفاظ جو محفوظ طریقے سے رکھے نہیں جا سکتے مواد کی بازیافت کے سیکشن میں ختم ہوتے ہیں تاکہ کچھ بھی نہ کھویا — پہلے اور بعد کی باقی گنتی ہمیشہ دکھائی جاتی ہے تاکہ آپ دیکھ سکیں کہ آیا اس نے مدد کی۔",
    "pdf_audit_view_formatted_report_btn": "نئے ٹیب میں قابل پرنٹ پہلے/بعد رسائی رپورٹ کھولتا ہے — اپنے ریکارڈز یا والدین کی میٹنگ کے لیے کاپی رکھنے کے لیے بینر میں PDF کے طور پر محفوظ کریں پر کلک کریں۔",
    "pdf_audit_view_html_report_btn": "پہلے/بعد کی رپورٹ کو HTML فائل کے طور پر ڈاؤن لوڈ کریں جسے آپ ویب سائٹ پر ہوسٹ یا ترمیم کر سکتے ہیں۔ مواد قابل پرنٹ PDF ورژن سے مماثل ہے۔",
    "pdf_audit_view_json_data_btn": "خام آڈٹ نمبرز اور قاعدہ بہ قاعدہ ڈیٹا کو JSON کے طور پر برآمد کریں۔ جب آپ اسپریڈ شیٹ، تحقیقی نوٹ بک، یا کسی اور ٹول میں رسائی کے نتائج کا تجزیہ کرنا چاہیں تو اسے استعمال کریں۔",
    "pdf_audit_view_audit_trail_signed_btn": "خود تصدیق کرنے والا آڈٹ ٹریل تیار کرتا ہے (ایک HTML فائل جس میں بلٹ ان درستگی کی تصدیق کا بٹن ہے جو چھیڑ چھاڑ کا پتہ لگاتا ہے)۔ تعمیل کے ثبوت کے طور پر اچھا — نوٹ کریں کہ یہ براؤزر سائیڈ دستخط ہے، قانونی طور پر پابند نہیں۔",
    "pdf_audit_view_save_project_btn": "آپ کا اصلاحی کام — قابل رسائی HTML، اسکورز، ترتیبات، صفحہ بہ صفحہ پیش رفت — کو ایک قابل حمل فائل میں محفوظ کرتا ہے۔ AI کو دوبارہ چلائے بغیر ترمیم جاری رکھنے کے لیے پراجیکٹ لوڈ کریں کے ساتھ دوبارہ کھولیں۔",
    "pdf_audit_view_load_project_btn": "وہ پراجیکٹ فائل دوبارہ کھولیں جو آپ نے پہلے محفوظ کی تھی۔ اصلاح شدہ HTML، اسکورز، اور کسی بھی پہلے سے مکمل صفحات کی رینج واپس لاتا ہے — آپ نے جہاں چھوڑا تھا وہاں سے بالکل جاری رہتا ہے۔",
    "pdf_audit_view_save_template_btn": "دستاویز کا قابل رسائی ڈھانچہ (عنوان کا خاکہ، جدول، فہرستیں، لینڈ مارکس) دوبارہ قابل استعمال ٹیمپلیٹ کے طور پر محفوظ کریں۔ نئی دستاویزات شروع کرنے کے لیے اسے Document Builder میں استعمال کریں — IEPs، syllabi — جو پہلے سے رسائی کے لیے پری اسٹرکچرڈ ہیں۔",
    "pdf_audit_alt_formats_summary": "متبادل فارمیٹس کے لیے پھیلائیں — ePub، الیکٹرانک بریل، سادہ متن، Markdown — ان طلباء کے لیے جنہیں PDF یا HTML کے علاوہ مختلف فائل قسم کی ضرورت ہے۔",
    "pdf_audit_alt_formats_epub_btn": "اصلاح شدہ دستاویز کو ePub فائل کے طور پر مواد کی فہرست اور رسائی میٹا ڈیٹا کے ساتھ محفوظ کریں۔ Kindle، Apple Books، اور زیادہ تر موبائل ریڈرز پر کام کرتا ہے — طلباء فونٹ کا سائز، رنگ، اور پڑھنے کی رفتار تبدیل کر سکتے ہیں۔",
    "pdf_audit_alt_formats_braille_btn": "گریڈ 1 (غیر سکڑا ہوا) بریل فائل محفوظ کریں جسے بریل پرنٹر پر ابھار کر چھاپا جا سکتا ہے یا قابل تازہ بریل ڈسپلے کو بھیجا جا سکتا ہے۔ گریڈ 2 سکڑاؤ کے لیے، ختم کرنے کے لیے فائل کو TVI (بصری معذوری والے طلباء کے استاد) کو دیں۔",
    "pdf_audit_alt_formats_text_btn": "تمام فارمیٹنگ ہٹا کر سادہ .txt فائل محفوظ کریں — اسکرین ریڈرز، بڑے پرنٹ کی تبدیلی، یا دوسرے ٹول میں چسپاں کرنے کے لیے سب سے آسان فارمیٹ۔",
    "pdf_audit_alt_formats_markdown_btn": "دستاویز کو Markdown کے طور پر محفوظ کریں — Canvas، Schoology، یا D2L صفحات، Google Docs (چسپاں کر کے)، wikis، اور GitHub طرز کے نوٹس میں عنوانات یا لنکس کھوئے بغیر صاف ستھرا داخل ہوتا ہے۔",
    "pdf_audit_alt_formats_daisy_btn": "DAISY 3 مکمل متن والا ٹاکنگ بُک پیکیج محفوظ کریں۔ DAISY ریڈرز (خصوصی تعلیم میں عام) مکمل نیویگیشن کے ساتھ اپنی تقریر، بریل، یا بڑے حروف خود فراہم کرتے ہیں۔ یہاں صرف متن ہے — ہم آہنگ پڑھ کر سنانے کے لیے Read-along ای بُک استعمال کریں۔",
    "pdf_audit_alt_formats_readalong_btn": "Read-along ای بُک بنائیں (EPUB3 میڈیا اوورلیز): ہر پیراگراف کو ٹیکسٹ ٹو اسپیچ کے ذریعے بیان کیا جاتا ہے اور متن کے ساتھ ہم آہنگ کیا جاتا ہے تاکہ بولے جانے کے ساتھ الفاظ نمایاں ہوں۔ فی حصہ ایک وائس کال، اس لیے اس میں کچھ منٹ لگ سکتے ہیں۔",
    "pdf_audit_alt_formats_odt_btn": "OpenDocument Text (.odt) فائل محفوظ کریں — LibreOffice اور Google Docs کے لیے موزوں (Word بھی اسے کھولتا ہے)۔ اسے اس وقت استعمال کریں جب آپ کا اسکول مکمل طور پر Microsoft پر نہ ہو مگر آپ پھر بھی ساخت برقرار رکھنے والی قابلِ تدوین دستاویز چاہتے ہوں۔"
